function getTemplate(id) {
  return BUILTIN_TEMPLATES[id];
}
function bindTemplate(template, bindings, resolve) {
  const valueFor = (slot) => {
    const b = bindings[slot];
    if (!b) throw new Error(`Template '${template.id}': slot '${slot}' is not bound`);
    return "const" in b ? b.const : resolve(b.ref);
  };
  const walk = (node) => {
    if (isLeafSlot(node)) return { const: valueFor(node.slot) };
    if (isNode(node)) return { op: node.op, args: node.args.map(walk) };
    return node;
  };
  return walk(template.expr);
}

// src/lib/measure/library.ts
var L = (en) => ({ ru: en, en });
function assembleLibrary(g) {
  const indicators = g.indicators;
  const byOwner = (kind, ref) => indicators.filter((i) => i.owner_kind === kind && i.owner_ref === ref);
  const ind = (kind, ref, key) => byOwner(kind, ref).find((i) => i.key === key);
  const technologies = {};
  for (const o of g.objects) {
    const capex = ind("object", o.id, "capex_ud");
    const maint = ind("object", o.id, "maintenance_capex_ud");
    technologies[o.id] = {
      id: o.id,
      name: L(o.name),
      kind: o.kind,
      description: o.description ? L(o.description) : void 0,
      rules: o.rules ? L(o.rules) : void 0,
      lifetimeYrs: o.lifetimeYrs,
      capex_ud: capex?.value,
      capex_ud_unit: capex?.unit,
      capex_ud_reference_ref: capex?.reference_ref,
      maintenance_capex_ud: maint?.value,
      eff: ind("object", o.id, "eff")?.value,
      indicators: byOwner("object", o.id).filter((i) => !["capex_ud", "maintenance_capex_ud"].includes(i.key)).map((i) => ({ key: i.key, label: L(i.key), value: i.value, unit: i.unit }))
    };
  }
  const resources = {};
  for (const r of g.resources) {
    resources[r.id] = {
      id: r.id,
      name: L(r.name),
      unit: r.unit,
      ef: ind("resource", r.id, "ef")?.value ?? 0,
      price: ind("resource", r.id, "price")?.value
    };
  }
  const products = {};
  for (const p of g.products) {
    const cf = ind("product", p.id, "carbon_footprint");
    products[p.id] = {
      id: p.id,
      name: L(p.name),
      unit: p.unit,
      service_unit: p.service_unit,
      carbon_footprint: cf ? { value: cf.value, unit: cf.unit ?? "" } : void 0
    };
  }
  const references = Object.fromEntries(g.references.map((r) => [r.id, r]));
  const pools = Object.fromEntries(
    g.pools.map((p) => [p.id, { ...p, sector: p.sector_ref }])
  );
  const subsectors = {};
  for (const s of g.subsectors) (subsectors[s.sector_ref] ??= []).push({ id: s.id, label: L(s.name) });
  return {
    resources,
    technologies,
    products,
    references,
    pools,
    checks: checks_default,
    indicators,
    subsectors,
    notation: measure_notation_default,
    // Templates live in code (the engine uses them); formula-templates.json mirrors them publicly.
    formulaTemplates: BUILTIN_TEMPLATES,
    globals: globals_default
  };
}
var library = assembleLibrary(graph_seed_default);
